import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Signup = () => {
  const { signup } = useAuth();
  const navigate = useNavigate();

  const [form, setForm] = useState({ name: "", email: "", password: "", confirmPassword: "" });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState("");

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = "Full name is required";
    if (!form.email) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Invalid email format";
    if (!form.password) e.password = "Password is required";
    else if (form.password.length < 6) e.password = "Minimum 6 characters";
    if (form.password !== form.confirmPassword) e.confirmPassword = "Passwords do not match";
    return e;
  };

  const onChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
    setApiError("");
  };

  const onSubmit = async e => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);
    try {
      await signup({ name: form.name, email: form.email, password: form.password });
      navigate("/");
    } catch (err) {
      setApiError(err.response?.data?.message || "Signup failed. Please try again.");
    } finally { setLoading(false); }
  };

  const inputStyle = (field) => ({
    background: "#1a1a2e",
    border: `1px solid ${errors[field] ? "#ff6584" : "#2a2a4a"}`,
    color: "#e8e8f0",
    borderRadius: 8
  });

  return (
    <div style={{ minHeight: "100vh", display: "flex" }}>
      {/* Left Panel */}
      <div className="d-none d-lg-flex flex-column justify-content-center p-5 flex-grow-1"
        style={{ background: "linear-gradient(135deg, #0d1117 0%, #161b22 100%)", borderRight: "1px solid #2a2a4a", maxWidth: "55%" }}>
        <Link to="/" className="d-flex align-items-center gap-2 fw-bold fs-5 mb-5 text-decoration-none">
          <span style={{ fontFamily: "JetBrains Mono, monospace", background: "rgba(108,99,255,0.15)", color: "#6c63ff", padding: "3px 10px", borderRadius: 6 }}>{"</>"}</span>
          <span style={{ color: "#e8e8f0" }}>CodeLearn</span>
        </Link>
        <h2 className="fw-bold mb-3" style={{ color: "#e8e8f0", fontSize: "2rem" }}>Start Learning Today</h2>
        <p className="mb-4" style={{ color: "#9999bb", lineHeight: 1.7, maxWidth: 400 }}>
          Join thousands of developers leveling up their skills with expert-led programming courses.
        </p>
        <div className="d-flex flex-column gap-3">
          {[
            { icon: "bi-rocket-takeoff-fill", text: "10+ expert programming courses", color: "#6c63ff" },
            { icon: "bi-bar-chart-fill", text: "Track your learning progress", color: "#43d9ad" },
            { icon: "bi-award-fill", text: "Certificates on completion", color: "#ffbb57" },
            { icon: "bi-check-circle-fill", text: "100% Free to get started", color: "#ff6584" }
          ].map((f, i) => (
            <div key={i} className="d-flex align-items-center gap-3 p-3 rounded-3"
              style={{ background: "rgba(108,99,255,0.06)", border: "1px solid #2a2a4a" }}>
              <i className={`bi ${f.icon}`} style={{ color: f.color, fontSize: "1.1rem" }}></i>
              <span className="small" style={{ color: "#9999bb" }}>{f.text}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Right Panel - Form */}
      <div className="d-flex align-items-center justify-content-center flex-grow-1 p-4"
        style={{ background: "#0f0f1a", minWidth: 340 }}>
        <div style={{ width: "100%", maxWidth: 400 }}>
          <h1 className="fw-bold mb-2" style={{ color: "#e8e8f0" }}>Create Account</h1>
          <p className="mb-4 small" style={{ color: "#9999bb" }}>
            Already have one? <Link to="/login" style={{ color: "#6c63ff", fontWeight: 600 }}>Log in</Link>
          </p>

          {apiError && (
            <div className="alert mb-4 small" style={{ background: "rgba(255,101,132,0.1)", border: "1px solid #ff6584", color: "#ff6584", borderRadius: 10 }}>
              <i className="bi bi-exclamation-circle me-2"></i>{apiError}
            </div>
          )}

          <form onSubmit={onSubmit} noValidate>
            {[
              { label: "Full Name", name: "name", type: "text", placeholder: "John Smith" },
              { label: "Email Address", name: "email", type: "email", placeholder: "you@example.com" },
              { label: "Password", name: "password", type: "password", placeholder: "Min. 6 characters" },
              { label: "Confirm Password", name: "confirmPassword", type: "password", placeholder: "Repeat password" }
            ].map(f => (
              <div className="mb-3" key={f.name}>
                <label className="form-label small fw-semibold" style={{ color: "#9999bb" }}>{f.label}</label>
                <input type={f.type} name={f.name} className="form-control" placeholder={f.placeholder}
                  value={form[f.name]} onChange={onChange} style={inputStyle(f.name)} />
                {errors[f.name] && <div className="mt-1 small" style={{ color: "#ff6584" }}>{errors[f.name]}</div>}
              </div>
            ))}

            <button type="submit" className="btn w-100 fw-bold py-3 mt-1" disabled={loading}
              style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 10, fontSize: "1rem" }}>
              {loading ? <><span className="spinner-border spinner-border-sm me-2"></span>Creating account...</> : "Create Account →"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Signup;
